/**
 * Táº¡m á»©ng â€” form controller.
 * Contract: docs/context/kt/tam-ung.md
 */
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useTamUngFormState } from './useTamUngFormState';
import { useLocation, useNavigate, useParams } from 'react-router-dom';
import { addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../../../store/hooks';
import { ktService } from '../../../../../services/kt/ktService';
import { createDepartmentSearchConfig } from '../../../../../components/search';
import { getApiErrorMessage } from '../../../../../utils/getApiErrorMessage';
import { useVoucherInitData } from '../../../../../hooks/useVoucherInitData';
import { FormMode, effectiveFormMode, fieldPlaceholder, isEditingMode, useFormFieldLock } from '../../../../../components/form';
import {
  buildVoucherCopyNavigateState,
  buildVoucherSearchNavigateState,
  useVoucherFormRoute,
  serializeVoucherSnapshot,
  snapshotsEqual,
  voucherSearchCacheToMap,
  type VoucherFormSnapshot,
} from '../../../../../components/voucher';
import { useUnsavedChangesGuard } from '../../../../../hooks/useUnsavedChangesGuard';
import type { CashVoucherDto, DocumentPostingStatus, UpdateAdvancePaymentDto } from '../../../../../services/kt/models';
import { tamUngLabels } from '../../../../../constants/tamUngLabels';
import type { AccountingPeriodDto } from '../../../../../services/kt/models';
import { validateVoucherDateAgainstPeriods } from '../../../../../utils/accountingPeriodDateValidation';
import { pollDocumentPostingStatus } from '../../../../../utils/pollDocumentPostingStatus';
import {
  validateTamUngFields,
  scrollToFirstTamUngFieldError,
  collectTamUngBannerMessages,
  validateTamUngHeaderField,
  validateTamUngLineField,
  TAM_UNG_LINE_GENERAL_ERROR,
  hasValidTamUngLine,
  shiftTamUngLineFieldErrors,
  insertLineFieldErrors,
  type TamUngFieldErrors,
  type TamUngHeaderFieldKey,
  type LineFieldKey,
  type LineFieldErrors,
} from '../../../../../utils/voucherFieldValidation';
import { tamUngInitFormName } from '../../../../../constants/tamUngInit';
import { resolveProcessingLevelSelectOptions } from '../../../../../utils/voucherProcessingLevelOptions';
import {
  buildVoucherToolbarDisabledReasons,
  isVoucherFormStatusLocked,
} from '../../../../../utils/voucherProcessingLevelDisplay';
import { TAM_UNG_CONFIG, tamUngTid, tamUngValidationBannerId } from '../config/tamUngConfig';
import {
  buildTamUngSavePayload,
  mapDtoToTamUngSnapshot,
  snapshotFromFormFields,
  tamUngToVoucherSnapshot,
  todayLocalDateInput,
  type TamUngSnapshot,
} from '../mappers/tamUngMappers';
import { emptyTamUngLine, type TamUngLineModel } from '../types/tamUngLine.types';
import styles from '../../../../../styles/documentForm.module.css';

const serializeTamUngSnapshot = (snap: TamUngSnapshot) =>
  serializeVoucherSnapshot(tamUngToVoucherSnapshot(snap));

export function useTamUngFormController() {
  const cfg = TAM_UNG_CONFIG;
  const LIST_PATH = cfg.listPath;
  const tid = tamUngTid;
  const validationBannerId = tamUngValidationBannerId;
  const { id } = useParams<{ id: string }>();
  const isNew = !id;
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const location = useLocation();

  const tamUngForm = useTamUngFormState(isNew);
  const {
    voucherDate,
    setVoucherDate,
    createdDate,
    setCreatedDate,
    voucherCode,
    setVoucherCode,
    customerId,
    setCustomerId,
    customerCode,
    setCustomerCode,
    customerName,
    setCustomerName,
    customerPhone,
    setCustomerPhone,
    creditAccountCode,
    setCreditAccountCode,
    creditAccountName,
    setCreditAccountName,
    description,
    setDescription,
    processingLevel,
    setProcessingLevel,
    status,
    setStatus,
    lines,
    setLines,
    patchLine,
    insertLineAfter,
    removeLineAt,
    lineRows,
    formMode,
    setFormMode,
    resetForm,
  } = tamUngForm;

  const toolbarMode = effectiveFormMode(isNew, formMode);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [showPrintModal, setShowPrintModal] = useState(false);
  const [showSearchSlideout, setShowSearchSlideout] = useState(false);
  const [approving, setApproving] = useState(false);
  const [printing, setPrinting] = useState(false);
  const [postingStatus, setPostingStatus] = useState<DocumentPostingStatus>('None');
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [savedSnapshot, setSavedSnapshot] = useState<string | null>(null);
  const [searchResultIds, setSearchResultIds] = useState<string[]>([]);
  const [accountingPeriods, setAccountingPeriods] = useState<AccountingPeriodDto[]>([]);
  const [fieldErrors, setFieldErrors] = useState<TamUngFieldErrors>({});
  const [generalErrors, setGeneralErrors] = useState<string[]>([]);
  const [validationErrors, setValidationErrors] = useState<string[]>([]);
  const [bannerExpanded, setBannerExpanded] = useState(true);
  const [bannerClosed, setBannerClosed] = useState(false);
  const [headerExpanded, setHeaderExpanded] = useState(true);
  const [selectedLineIndex, setSelectedLineIndex] = useState(0);
  const [highlightLineId, setHighlightLineId] = useState<string | null>(null);
  const expandHeaderAfterSaveRef = useRef(false);
  const searchCacheRef = useRef<Map<string, CashVoucherDto>>(new Map());

  useEffect(() => {
    const msgs = collectTamUngBannerMessages(fieldErrors, generalErrors);
    setValidationErrors(prev => {
      if (prev.length === msgs.length && msgs.every((m, i) => prev[i] === m)) return prev;
      return msgs;
    });
    if (msgs.length === 0) {
      setBannerClosed(prev => (prev ? prev : true));
    }
  }, [fieldErrors, generalErrors]);

  useEffect(() => {
    if (!hasValidTamUngLine(lines)) return;
    setGeneralErrors(ge => {
      if (!ge.includes(TAM_UNG_LINE_GENERAL_ERROR)) return ge;
      return ge.filter(m => m !== TAM_UNG_LINE_GENERAL_ERROR);
    });
  }, [lines]);

  useEffect(() => {
    if (!highlightLineId) return undefined;
    const timer = window.setTimeout(() => setHighlightLineId(null), 2200);
    return () => window.clearTimeout(timer);
  }, [highlightLineId]);

  useEffect(() => {
    if (selectedLineIndex >= lines.length) {
      setSelectedLineIndex(Math.max(0, lines.length - 1));
    }
  }, [lines.length, selectedLineIndex]);

  const clearAllValidation = useCallback(() => {
    setFieldErrors({});
    setGeneralErrors([]);
    setValidationErrors([]);
    setBannerClosed(true);
  }, []);

  const patchHeaderFieldError = useCallback((key: TamUngHeaderFieldKey, value: string) => {
    const msg = validateTamUngHeaderField(key, value);
    setFieldErrors(prev => {
      const next = { ...prev };
      if (msg) next[key] = msg;
      else delete next[key];
      return next;
    });
  }, []);

  const patchLineFieldError = useCallback((
    lineIndex: number,
    key: LineFieldKey,
    line: { accountCode: string; amount: number },
  ) => {
    const msg = validateTamUngLineField(lineIndex, key, line);
    setFieldErrors(prev => {
      const next: TamUngFieldErrors = { ...prev, lines: { ...prev.lines } };
      const row = { ...(next.lines?.[lineIndex] ?? {}) };
      if (msg) row[key] = msg;
      else delete row[key];
      if (Object.keys(row).length === 0) {
        if (next.lines) delete next.lines[lineIndex];
        if (next.lines && Object.keys(next.lines).length === 0) delete next.lines;
      } else {
        next.lines = next.lines ?? {};
        next.lines[lineIndex] = row;
      }
      return next;
    });
  }, []);

  const initFormName = tamUngInitFormName(isNew);
  const { processingLevelOptions, departmentOptions, defaultProcessingLevel, formPermissions } =
    useVoucherInitData(initFormName);

  const departmentSearchConfig = useMemo(
    () => createDepartmentSearchConfig(departmentOptions),
    [departmentOptions],
  );

  const processingOpts = useMemo(
    () => resolveProcessingLevelSelectOptions(processingLevelOptions, defaultProcessingLevel),
    [processingLevelOptions, defaultProcessingLevel],
  );

  const totalAmount = useMemo(
    () => lines.reduce((sum, line) => sum + (Number(line.amount) || 0), 0),
    [lines],
  );

  const saveLabel = tamUngLabels.saveButton;

  const resolveProcessingLevelForSave = useCallback((): string => {
    if (processingLevel) return processingLevel;
    return defaultProcessingLevel ?? '';
  }, [processingLevel, defaultProcessingLevel]);

  const buildSavePayload = useCallback((level?: string): UpdateAdvancePaymentDto => {
    const resolvedLevel = level ?? resolveProcessingLevelForSave();
    return buildTamUngSavePayload({
      voucherDate,
      createdDate,
      creditAccountCode,
      customerId,
      description,
      processingLevel: resolvedLevel,
      lines,
    });
  }, [
    resolveProcessingLevelForSave,
    lines,
    voucherDate,
    createdDate,
    creditAccountCode,
    customerId,
    description,
  ]);

  const isStatusLocked =
    status === 'Settled' || isVoucherFormStatusLocked(status, processingLevel);
  /** Tạm ứng ERP: auto post event — không nút Ghi sổ toolbar (§8.16). */
  const showPostButton = false;
  const canViewLedgerToolbar =
    !isNew &&
    (status === 'Posted' || postingStatus !== 'None') &&
    (formPermissions?.canViewLedger ?? false);
  const toolbarDisabledReasons = useMemo(
    () => buildVoucherToolbarDisabledReasons({ isNew, status, showPostButton, isStatusLocked }),
    [isNew, status, isStatusLocked],
  );
  const { isViewMode, isReadOnly, fieldLockProps, staticFieldProps, searchDisabled, selectDisabled, textareaReadOnly, textareaDisabled } = useFormFieldLock({
    formMode: toolbarMode,
    isStatusLocked,
  });

  const ph = (text: string) => fieldPlaceholder(toolbarMode, text, { isStatusLocked });

  const lineRowForValidate = (row: TamUngLineModel) => ({
    accountCode: row.accountCode,
    amount: row.amount,
  });

  const updateLine = (idx: number, patch: Partial<TamUngLineModel>) => {
    patchLine(idx, patch);
    const updated = { ...lines[idx], ...patch };
    if (updated) {
      if ('accountCode' in patch || 'accountName' in patch) {
        patchLineFieldError(idx, 'accountCode', lineRowForValidate(updated));
      }
      if ('amount' in patch) {
        patchLineFieldError(idx, 'debitAmount', lineRowForValidate(updated));
      }
    }
  };

  const removeLine = (idx: number) => {
    if (lines.length <= 1) {
      dispatch(addToast({ message: tamUngLabels.validationLines, type: 'warning' }));
      return;
    }
    const removedId = lineRows[idx]?.lineId;
    removeLineAt(idx);
    const nextLines = lines.filter((_, i) => i !== idx);
    setFieldErrors(prev => {
      const next: TamUngFieldErrors = { ...prev };
      if (!next.lines) return next;
      const shifted = shiftTamUngLineFieldErrors(next.lines, idx);
      if (!shifted) {
        delete next.lines;
        return next;
      }
      const reindexed: Record<number, LineFieldErrors> = {};
      Object.keys(shifted).forEach(key => {
        const i = Number(key);
        const row = nextLines[i];
        if (!row) return;
        const le: LineFieldErrors = {};
        if (shifted[i]?.accountCode) {
          const msg = validateTamUngLineField(i, 'accountCode', lineRowForValidate(row));
          if (msg) le.accountCode = msg;
        }
        if (shifted[i]?.debitAmount) {
          const msg = validateTamUngLineField(i, 'debitAmount', lineRowForValidate(row));
          if (msg) le.debitAmount = msg;
        }
        if (Object.keys(le).length > 0) reindexed[i] = le;
      });
      if (Object.keys(reindexed).length > 0) next.lines = reindexed;
      else delete next.lines;
      return next;
    });
    setSelectedLineIndex(prev => {
      if (prev > idx) return prev - 1;
      if (prev === idx) return Math.max(0, idx - 1);
      return prev;
    });
    if (removedId && highlightLineId === removedId) {
      setHighlightLineId(null);
    }
  };

  const handleAddLine = () => {
    if (lines.length === 0) return;
    const afterIdx = selectedLineIndex >= 0 && selectedLineIndex < lines.length
      ? selectedLineIndex
      : lines.length - 1;
    const insertAt = afterIdx + 1;
    const lineId = insertLineAfter(afterIdx);
    const shifted = insertLineFieldErrors(fieldErrors.lines, insertAt);
    setFieldErrors({ ...fieldErrors, lines: shifted });
    setSelectedLineIndex(insertAt);
    setHighlightLineId(lineId);
    setGeneralErrors(ge => ge.filter(m => m !== TAM_UNG_LINE_GENERAL_ERROR));
  };

  const handleCopyLine = () => {
    if (lines.length === 0) return;
    const afterIdx = selectedLineIndex >= 0 && selectedLineIndex < lines.length
      ? selectedLineIndex
      : lines.length - 1;
    const source = lines[afterIdx];
    if (!source) return;
    const insertAt = afterIdx + 1;
    const lineId = insertLineAfter(afterIdx, { ...source });
    const shifted = insertLineFieldErrors(fieldErrors.lines, insertAt);
    setFieldErrors({ ...fieldErrors, lines: shifted });
    setSelectedLineIndex(insertAt);
    setHighlightLineId(lineId);
    setGeneralErrors(ge => ge.filter(m => m !== TAM_UNG_LINE_GENERAL_ERROR));
  };

  const handleSelectLine = (idx: number) => setSelectedLineIndex(idx);

  const viewSectionClass = isViewMode ? styles.viewReadOnlySection : '';

  const buildSnapshot = useCallback(
    (): TamUngSnapshot => snapshotFromFormFields({
      voucherDate,
      createdDate,
      customerId,
      customerCode,
      customerName,
      customerPhone,
      creditAccountCode,
      creditAccountName,
      description,
      processingLevel,
      lines,
    }),
    [
      voucherDate, createdDate, customerId, customerCode, customerName, customerPhone,
      creditAccountCode, creditAccountName, description, processingLevel, lines,
    ],
  );

  const currentSnapshotSerialized = useMemo(
    () => serializeTamUngSnapshot(buildSnapshot()),
    [buildSnapshot],
  );

  const isDirty = savedSnapshot !== null && !snapshotsEqual(savedSnapshot, currentSnapshotSerialized);

  const markSnapshotSaved = useCallback(() => {
    setSavedSnapshot(serializeTamUngSnapshot(buildSnapshot()));
  }, [buildSnapshot]);

  const {
    showUnsavedModal,
    guardedAction,
    confirmLeave,
    cancelLeave,
  } = useUnsavedChangesGuard(isDirty, isEditingMode(toolbarMode));

  const applySnapshot = useCallback((snapshot: TamUngSnapshot, resetSaved = false) => {
    setVoucherDate(snapshot.voucherDate);
    setCreatedDate(snapshot.createdDate || todayLocalDateInput());
    setCustomerId(snapshot.customerId);
    setCustomerCode(snapshot.customerCode);
    setCustomerName(snapshot.customerName);
    setCustomerPhone(snapshot.customerPhone);
    setCreditAccountCode(snapshot.creditAccountCode || '141');
    setCreditAccountName(snapshot.creditAccountName);
    setDescription(snapshot.description);
    setProcessingLevel(snapshot.processingLevel);
    setLines(snapshot.lines.length > 0 ? snapshot.lines : [emptyTamUngLine()]);
    if (resetSaved) {
      setVoucherCode('');
      setStatus('Draft');
      setSavedSnapshot(serializeTamUngSnapshot({
        ...snapshot,
        createdDate: todayLocalDateInput(),
      }));
    }
  }, []);

  const resetEmptyForm = useCallback(() => {
    setVoucherDate(todayLocalDateInput());
    setCreatedDate(todayLocalDateInput());
    setVoucherCode('');
    setCustomerId('');
    setCustomerCode('');
    setCustomerName('');
    setCustomerPhone('');
    setCreditAccountCode('141');
    setCreditAccountName('');
    setDescription('');
    setProcessingLevel(defaultProcessingLevel || '');
    setStatus('Draft');
    setLines([emptyTamUngLine()]);
    setSavedSnapshot(null);
  }, [defaultProcessingLevel]);

  const closeOverlays = useCallback(() => {
    setShowSearchSlideout(false);
    setShowApproveModal(false);
    setShowPrintModal(false);
    setShowDeleteModal(false);
  }, []);

  const applyCopySnapshot = useCallback(
    (snap: TamUngSnapshot) => applySnapshot(snap, true),
    [applySnapshot],
  );

  /** Baseline sau resetEmptyForm + flush state (trÃ¡nh snapshot cÅ© trong cÃ¹ng tick). */
  const scheduleInitialBaseline = useCallback(() => {
    setTimeout(() => markSnapshotSaved(), 0);
  }, [markSnapshotSaved]);

  const { copySourceVoucherCode } = useVoucherFormRoute<TamUngSnapshot>({
    isNew,
    id,
    location,
    navigate,
    setFormMode,
    setSearchResultIds,
    resetEmptyForm,
    applyCopySnapshot,
    initNewSavedSnapshot: scheduleInitialBaseline,
    onRouteChange: closeOverlays,
  });

  useEffect(() => {
    if (!isNew || !defaultProcessingLevel || processingLevel) return;
    setProcessingLevel(defaultProcessingLevel);
  }, [isNew, defaultProcessingLevel, processingLevel, setProcessingLevel]);

  useEffect(() => {
    if (!saving && expandHeaderAfterSaveRef.current) {
      setHeaderExpanded(true);
      expandHeaderAfterSaveRef.current = false;
    }
  }, [saving, id, formMode]);

  useEffect(() => {
    let cancelled = false;
    const timer = setTimeout(() => {
      ktService.getPeriods()
        .then(periods => { if (!cancelled) setAccountingPeriods(periods); })
        .catch(() => { /* non-blocking â€” BE validates on save */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, []);

  const reloadVoucherFromServer = useCallback(async (voucherId: string) => {
    const dto = await cfg.get(voucherId);
    const snapshot = mapDtoToTamUngSnapshot(dto);
    applySnapshot(snapshot);
    setVoucherCode(dto.code);
    setStatus((dto.status as 'Draft' | 'Posted' | 'Settled') ?? 'Draft');
    setSavedSnapshot(serializeTamUngSnapshot(snapshot));
  }, [cfg, applySnapshot, setVoucherCode, setStatus]);

  const refreshPostingStatusAfterLevelChange = useCallback(async (
    previousLevel: string,
    newLevel: string,
    voucherId?: string,
  ) => {
    if (!voucherId) return;
    const wasAutoPost = previousLevel === '9';
    const isAutoPost = newLevel === '9';
    try {
      if (isAutoPost) {
        const ps = await cfg.getPostingStatus(voucherId);
        setPostingStatus(ps.postingStatus);
        if (ps.postingStatus === 'Queued' || ps.postingStatus === 'Processing') {
          const final = await pollDocumentPostingStatus(() => cfg.getPostingStatus(voucherId));
          setPostingStatus(final.postingStatus);
          if (final.postingStatus === 'Failed' && final.lastError) {
            dispatch(addToast({ message: final.lastError, type: 'error' }));
          }
          if (final.postingStatus === 'Posted') {
            await reloadVoucherFromServer(voucherId);
          }
        } else if (ps.postingStatus === 'Posted') {
          await reloadVoucherFromServer(voucherId);
        }
      } else if (wasAutoPost && !isAutoPost) {
        const final = await pollDocumentPostingStatus(() => cfg.getPostingStatus(voucherId));
        setPostingStatus(final.postingStatus);
        if (final.postingStatus === 'Failed' && final.lastError) {
          dispatch(addToast({ message: final.lastError, type: 'error' }));
          return;
        }
        await reloadVoucherFromServer(voucherId);
      }
    } catch {
      /* optional — không chặn form */
    }
  }, [cfg, dispatch, reloadVoucherFromServer]);

  useEffect(() => {
    if (isNew || !id) {
      setPostingStatus('None');
      return;
    }
    let cancelled = false;
    const t = setTimeout(() => {
      void (async () => {
        try {
          const ps = await cfg.getPostingStatus(id);
          if (!cancelled) setPostingStatus(ps.postingStatus);
        } catch {
          /* optional */
        }
      })();
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, isNew, cfg]);

  useEffect(() => {
    if (isNew) return;
    let cancelled = false;
    setLoading(true);
    const timer = setTimeout(() => {
      cfg.get(id!)
        .then(dto => {
          if (cancelled) return;
          const snapshot = mapDtoToTamUngSnapshot(dto);
          applySnapshot(snapshot);
          setVoucherCode(dto.code);
          setStatus((dto.status as 'Draft' | 'Posted' | 'Settled') ?? 'Draft');
          setFormMode(FormMode.View);
          setSavedSnapshot(serializeTamUngSnapshot(snapshot));
          clearAllValidation();
        })
        .catch(error => {
          if (cancelled) return;
          dispatch(addToast({ message: getApiErrorMessage(error, tamUngLabels.loadError), type: 'error' }));
          navigate(LIST_PATH);
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, [dispatch, id, isNew, navigate, clearAllValidation]);

  const handleSave = async () => {
    if (!isEditingMode(toolbarMode)) {
      dispatch(addToast({
        message: 'Nháº¥n Sá»­a Ä‘á»ƒ chá»‰nh sá»­a trÆ°á»›c khi lÆ°u',
        type: 'warning',
      }));
      return;
    }

    const level = resolveProcessingLevelForSave();
    if (!processingLevel && level) {
      setProcessingLevel(level);
    }

    const validation = validateTamUngFields({
      voucherDate,
      customerId,
      creditAccountCode,
      description: description.trim(),
      processingLevel: level,
      lines: lines.map(l => ({ accountCode: l.accountCode, amount: l.amount })),
    });

    const periodError = validateVoucherDateAgainstPeriods(voucherDate, accountingPeriods);
    const general = validation.bannerMessages.filter(m => m === TAM_UNG_LINE_GENERAL_ERROR);
    const hasFieldOrLineErrors = validation.bannerMessages.some(m => m !== TAM_UNG_LINE_GENERAL_ERROR);

    if (hasFieldOrLineErrors || general.length > 0 || periodError) {
      setFieldErrors(validation.fieldErrors);
      setGeneralErrors(periodError ? [...general, periodError] : general);
      setBannerClosed(false);
      setBannerExpanded(true);
      const bannerMsgs = collectTamUngBannerMessages(
        validation.fieldErrors,
        periodError ? [...general, periodError] : general,
      );
      dispatch(addToast({
        message: bannerMsgs[0] ?? tamUngLabels.validationRequired,
        type: 'error',
      }));
      if (hasFieldOrLineErrors) {
        scrollToFirstTamUngFieldError(validation.fieldErrors, tid, validationBannerId);
      } else {
        setTimeout(() => {
          document.getElementById(validationBannerId)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }, 120);
      }
      return;
    }

    clearAllValidation();
    expandHeaderAfterSaveRef.current = true;
    setSaving(true);
    try {
      const payload = buildSavePayload(level);
      if (isNew) {
        const created = await cfg.create(payload);
        if (!created?.id) {
          dispatch(addToast({ message: tamUngLabels.saveError, type: 'error' }));
          return;
        }
        setVoucherCode(created.code);
        setStatus('Draft');
        setFormMode(FormMode.View);
        markSnapshotSaved();
        clearAllValidation();
        dispatch(addToast({ message: tamUngLabels.saveSuccessCreate, type: 'success' }));
        navigate(`${LIST_PATH}/${created.id}`);
        void refreshPostingStatusAfterLevelChange('', level, created.id);
      } else if (id) {
        await cfg.update(id, payload);
        setFormMode(FormMode.View);
        markSnapshotSaved();
        clearAllValidation();
        dispatch(addToast({ message: tamUngLabels.saveSuccessUpdate, type: 'success' }));
        void refreshPostingStatusAfterLevelChange(processingLevel, level, id);
      }
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, tamUngLabels.saveError), type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (isNew || !id) return;
    setDeleting(true);
    try {
      await cfg.remove(id);
      dispatch(addToast({ message: tamUngLabels.deleteSuccess, type: 'success' }));
      navigate(LIST_PATH);
    } catch (error: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(error, tamUngLabels.deleteError), type: 'error' }));
    } finally {
      setDeleting(false);
      setShowDeleteModal(false);
    }
  };

  const handleApproveConfirm = async (newLevel: string) => {
    setApproving(true);
    const previousLevel = processingLevel;
    try {
      if (!isNew && id) {
        await cfg.update(id, buildSavePayload(newLevel));
        setProcessingLevel(newLevel);
        markSnapshotSaved();
        dispatch(addToast({ message: tamUngLabels.approveLevelSuccess, type: 'success' }));
        void refreshPostingStatusAfterLevelChange(previousLevel, newLevel, id);
      } else {
        setProcessingLevel(newLevel);
        setSavedSnapshot(serializeTamUngSnapshot({ ...buildSnapshot(), processingLevel: newLevel }));
        dispatch(addToast({
          message: tamUngLabels.approveLevelPendingSave,
          type: 'success',
        }));
      }
      setShowApproveModal(false);
    } catch (error: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(error, tamUngLabels.approveLevelError), type: 'error' }));
    } finally {
      setApproving(false);
    }
  };

  const searchNavIndex = id ? searchResultIds.indexOf(id) : -1;
  const hasSearchNav = searchNavIndex >= 0 && searchResultIds.length > 0;

  const navigateToSearchId = (targetId: string) => {
    guardedAction(() => navigate(
      `${LIST_PATH}/${targetId}`,
      { state: buildVoucherSearchNavigateState(searchResultIds) },
    ));
  };

  const revertToSaved = useCallback(() => {
    if (!savedSnapshot) return;
    try {
      const parsed = JSON.parse(savedSnapshot) as VoucherFormSnapshot;
      const snap: TamUngSnapshot = {
        voucherDate: parsed.voucherDate,
        createdDate,
        customerId: parsed.customerId,
        customerCode: parsed.customerCode,
        customerName: parsed.customerName,
        customerPhone: parsed.customerPhone,
        creditAccountCode: parsed.accountCode,
        creditAccountName: parsed.accountName ?? '',
        description: parsed.description,
        processingLevel: parsed.processingLevel,
        lines: parsed.lines.map(l => ({
          accountCode: l.accountCode,
          accountName: l.accountName ?? '',
          amount: l.debitAmount,
          description: l.description,
          costCenterCode: l.costCenterCode ?? '',
        })),
      };
      applySnapshot(snap);
    } catch {
      /* ignore corrupt snapshot */
    }
  }, [savedSnapshot, createdDate, applySnapshot]);

  const handleOpenFromSearch = (voucherId: string, resultIds: string[], items: CashVoucherDto[]) => {
    searchCacheRef.current = voucherSearchCacheToMap(items);
    setSearchResultIds(resultIds);
    guardedAction(() => navigate(
      `${LIST_PATH}/${voucherId}`,
      { state: buildVoucherSearchNavigateState(resultIds, items) },
    ));
  };

  const handleBack = () => guardedAction(() => {
    setSearchResultIds([]);
    navigate(LIST_PATH);
  });
  const handleNew = () => guardedAction(() => navigate(`${LIST_PATH}/them`));
  const handleCopy = () => {
    guardedAction(() => {
      navigate(
        `${LIST_PATH}/them`,
        { state: buildVoucherCopyNavigateState(buildSnapshot(), voucherCode) },
      );
    });
  };

  const handleCancel = () => {
    if (formMode === FormMode.Edit) {
      revertToSaved();
      setFormMode(FormMode.View);
      return;
    }
    navigate(LIST_PATH);
  };

  const handlePrintConfirm = async (templateId: string) => {
    setPrinting(true);
    try {
      dispatch(addToast({
        message: `In PDF (placeholder) â€” máº«u: ${templateId}. Triá»ƒn khai preview/PDF sau.`,
        type: 'info',
      }));
      setShowPrintModal(false);
    } finally {
      setPrinting(false);
    }
  };

  const fetchSearchList = async (f?: Parameters<typeof cfg.list>[0]) => {
    const res = await cfg.list({
      ...f,
      pageSize: f?.pageSize ?? 20,
    });
    return {
      items: res.items as unknown as CashVoucherDto[],
      totalCount: res.totalCount,
    };
  };

  return {
    cfg,
    labels: tamUngLabels,
    styles,
    isNew,
    id,
    showInitialLoading: loading,
    tid,
    validationBannerId,
    LIST_PATH,
    voucherDate,
    setVoucherDate,
    createdDate,
    voucherCode,
    customerId,
    setCustomerId,
    customerCode,
    setCustomerCode,
    customerName,
    setCustomerName,
    customerPhone,
    setCustomerPhone,
    creditAccountCode,
    setCreditAccountCode,
    creditAccountName,
    setCreditAccountName,
    description,
    setDescription,
    processingLevel,
    setProcessingLevel,
    status,
    lines,
    formMode,
    setFormMode,
    toolbarMode,
    saving,
    deleting,
    approving,
    printing,
    saveLabel,
    fieldErrors,
    patchHeaderFieldError,
    updateLine,
    removeLine,
    handleAddLine,
    handleCopyLine,
    handleSelectLine,
    lineRows,
    selectedLineIndex,
    highlightLineId,
    headerExpanded,
    setHeaderExpanded,
    formPermissions,
    totalAmount,
    processingOpts,
    departmentSearchConfig,
    departmentOptions,
    isStatusLocked,
    isViewMode,
    isReadOnly,
    fieldLockProps,
    staticFieldProps,
    searchDisabled,
    selectDisabled,
    textareaReadOnly,
    textareaDisabled,
    ph,
    viewSectionClass,
    validationErrors,
    bannerClosed,
    bannerExpanded,
    setBannerExpanded,
    setBannerClosed,
    showDeleteModal,
    setShowDeleteModal,
    showApproveModal,
    setShowApproveModal,
    showPrintModal,
    setShowPrintModal,
    showSearchSlideout,
    setShowSearchSlideout,
    showUnsavedModal,
    cancelLeave,
    confirmLeave,
    hasSearchNav,
    searchNavIndex,
    searchResultIds,
    navigateToSearchId,
    handleBack,
    handleNew,
    handleCopy,
    handleSave,
    handleCancel,
    handleDelete,
    handleApproveConfirm,
    handleOpenFromSearch,
    handlePrintConfirm,
    fetchSearchList,
    showPostButton,
    canViewLedger: canViewLedgerToolbar,
    showLedgerModal,
    setShowLedgerModal,
    postingStatus,
    toolbarDisabledReasons,
    copySourceVoucherCode,
  };
}

export type TamUngFormViewModel = ReturnType<typeof useTamUngFormController>;
