import React from 'react';
import { Input } from '@linm-soft/common-components';
import { VoucherDescriptionField } from '../../../../../components/voucher';
import { CustomerSearchField, AccountSearchInput, erpFinanceAccountSearchApi } from '../../../../../components/search';
import { formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import type { TamUngFormViewModel } from '../hooks/useTamUngFormController';

export const TamUngHeaderSection: React.FC<{ vm: TamUngFormViewModel }> = ({ vm }) => {
  const {
    labels,
    tid,
    styles: df,
    viewSectionClass,
    voucherDate,
    setVoucherDate,
    fieldErrors,
    patchHeaderFieldError,
    fieldLockProps,
    voucherCode,
    ph,
    staticFieldProps,
    createdDate,
    isViewMode,
    customerId,
    customerCode,
    customerName,
    setCustomerId,
    setCustomerCode,
    setCustomerName,
    customerPhone,
    setCustomerPhone,
    searchDisabled,
    creditAccountCode,
    creditAccountName,
    setCreditAccountCode,
    setCreditAccountName,
    description,
    setDescription,
    textareaReadOnly,
    textareaDisabled,
    headerExpanded,
    setHeaderExpanded,
  } = vm;

  const useCompactHeader = true;
  const compactHideClass = (visibleWhenCompact: boolean) =>
    useCompactHeader && !headerExpanded && !visibleWhenCompact ? df.headerCompactHidden : undefined;

  const fieldClass = (...parts: (string | false | undefined)[]) =>
    [df.field, ...parts].filter(Boolean).join(' ');

  const headerToggle = (
    <button
      type="button"
      className={df.headerToggleBtn}
      data-testid={tid(headerExpanded ? 'header-collapse' : 'header-expand')}
      aria-expanded={headerExpanded}
      onClick={() => setHeaderExpanded(v => !v)}
    >
      <span className={df.headerToggleIcon} aria-hidden>
        <i className={headerExpanded ? 'fas fa-chevron-up' : 'fas fa-chevron-down'} />
      </span>
      {headerExpanded ? labels.headerCollapse : labels.headerExpand}
    </button>
  );

  const sectionClass = [
    df.section,
    viewSectionClass,
    useCompactHeader && !headerExpanded ? df.headerCompactActive : undefined,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <div
      className={sectionClass}
      id={tid('section-header')}
      data-testid={tid('section-header')}
    >
      <div className={df.sectionTitleRow}>
        <h2 className={df.sectionTitle}>{labels.sectionInfo}</h2>
        {headerToggle}
      </div>

      <div className={df.headerFieldsFlow}>
        <div className={df.row4}>
          <div
            id={tid('field-voucherDate')}
            className={fieldClass(compactHideClass(true))}
            data-testid={tid('field-voucherDate')}
          >
            <label className={df.label}>{labels.voucherDate}</label>
            <Input
              type="date"
              value={voucherDate}
              error={fieldErrors.voucherDate}
              onChange={e => {
                const v = e.target.value;
                setVoucherDate(v);
                patchHeaderFieldError('voucherDate', v);
              }}
              {...fieldLockProps}
            />
          </div>
          <div className={fieldClass(compactHideClass(false))}>
            <label className={df.label}>{labels.voucherCode}</label>
            <Input
              value={voucherCode}
              placeholder={ph(labels.phAutoCode)}
              data-testid={tid('field-voucherCode')}
              {...staticFieldProps}
            />
          </div>
          <div className={fieldClass(compactHideClass(false))} data-testid={tid('field-createdDate')}>
            <label className={df.label}>{labels.createdDate}</label>
            <Input type="date" value={createdDate} {...staticFieldProps} />
          </div>
          <div className={df.field} aria-hidden />
        </div>

        <div className={df.row4}>
          <div
            id={tid('field-customerId')}
            className={fieldClass(df.spanCol2, compactHideClass(true))}
            data-testid={tid('field-customerId')}
          >
            <label className={df.label}>{labels.customer}</label>
            <CustomerSearchField
              testIdPrefix={tid('customer')}
              className={isViewMode ? df.searchViewOnly : undefined}
              customerId={customerId}
              customerCode={customerCode}
              customerName={customerName}
              error={fieldErrors.customerId}
              onSelect={c => {
                setCustomerId(c.customerId);
                setCustomerCode(c.code);
                setCustomerName(c.name);
                setCustomerPhone(c.phone ?? '');
                patchHeaderFieldError('customerId', c.customerId);
              }}
              onClear={() => {
                setCustomerId('');
                setCustomerCode('');
                setCustomerName('');
                setCustomerPhone('');
                patchHeaderFieldError('customerId', '');
              }}
              placeholder={ph(labels.phCustomer)}
              disabled={searchDisabled}
            />
          </div>
          <div className={fieldClass(compactHideClass(false))} data-testid={tid('field-customerPhone')}>
            <label className={df.label}>{labels.customerPhone}</label>
            <Input
              value={customerPhone}
              onChange={e => setCustomerPhone(e.target.value)}
              {...fieldLockProps}
            />
          </div>
          <div className={df.field} aria-hidden />
        </div>

        <div className={df.row4}>
          <div
            id={tid('field-creditAccountCode')}
            className={fieldClass(compactHideClass(true))}
            data-testid={tid('field-creditAccountCode')}
          >
            <label className={df.label}>{labels.creditAccount}</label>
            <AccountSearchInput
              api={erpFinanceAccountSearchApi}
              className={df.lineAccountSearch}
              value={creditAccountCode}
              primaryDisplay={formatAccountDisplay(creditAccountCode, creditAccountName)}
              error={fieldErrors.creditAccountCode}
              onChange={a => {
                setCreditAccountCode(a.code);
                setCreditAccountName(a.name);
                patchHeaderFieldError('creditAccountCode', a.code);
              }}
              onClear={() => {
                setCreditAccountCode('');
                setCreditAccountName('');
                patchHeaderFieldError('creditAccountCode', '');
              }}
              showLabel={false}
              showSecondaryInput={false}
              placeholder={ph(labels.phCreditAccount)}
              disabled={searchDisabled}
            />
          </div>
          <div
            id={tid('field-description')}
            className={fieldClass(df.spanCol3, compactHideClass(false))}
            data-testid={tid('field-description')}
          >
            <label className={df.label}>{labels.description}</label>
            <VoucherDescriptionField
              value={description}
              error={fieldErrors.description}
              onChange={v => {
                setDescription(v);
                patchHeaderFieldError('description', v);
              }}
              readOnly={textareaReadOnly}
              disabled={textareaDisabled}
            />
          </div>
        </div>
      </div>
    </div>
  );
};
